{
  "name": "Ideal Tecidos - Controle de Estoque",
  "description": "Um aplicativo intuitivo e confiável para contagem manual e controle de estoque de lojas de confecção, otimizado para dispositivos móveis com geração de relatórios PDF."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type SizeGridType = 'LETTER' | 'NUMERIC';

export interface InventoryCount {
  id: string;
  productType: string;
  model: string;
  brand?: string;
  color?: string;
  observations?: string;
  gridType: SizeGridType;
  sizes: Record<string, number>;
  total: number;
  createdAt: number;
}

export enum AppView {
  HOME = 'HOME',
  IDENTIFY = 'IDENTIFY',
  COUNT = 'COUNT',
  HISTORY = 'HISTORY',
  EDIT = 'EDIT'
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  Package, 
  History, 
  Plus, 
  Trash2, 
  Edit2, 
  ChevronLeft, 
  Save, 
  FileText, 
  Search,
  XCircle
} from 'lucide-react';
import { AppView, InventoryCount, SizeGridType } from './types';
import { PRODUCT_TYPES, LETTER_SIZES, NUMERIC_SIZES } from './constants';

const App: React.FC = () => {
  // Persistence state
  const [counts, setCounts] = useState<InventoryCount[]>(() => {
    const saved = localStorage.getItem('ideal_tecidos_inventory');
    return saved ? JSON.parse(saved) : [];
  });

  // UI state
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [searchTerm, setSearchTerm] = useState('');

  // Form state
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<InventoryCount>>({
    productType: '',
    model: '',
    brand: '',
    color: '',
    observations: '',
    gridType: 'LETTER',
    sizes: {},
    total: 0
  });

  // Save to localStorage
  useEffect(() => {
    localStorage.setItem('ideal_tecidos_inventory', JSON.stringify(counts));
  }, [counts]);

  // Handlers
  const handleStartNew = () => {
    setFormData({
      productType: '',
      model: '',
      brand: '',
      color: '',
      observations: '',
      gridType: 'LETTER',
      sizes: {},
      total: 0
    });
    setEditingId(null);
    setCurrentView(AppView.IDENTIFY);
  };

  const handleEdit = (count: InventoryCount) => {
    setFormData({ ...count });
    setEditingId(count.id);
    setCurrentView(AppView.IDENTIFY);
  };

  const handleDelete = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta contagem?')) {
      setCounts(prev => prev.filter(c => c.id !== id));
    }
  };

  const updateSizeCount = (size: string, value: string) => {
    const num = parseInt(value, 10) || 0;
    const cleanNum = Math.max(0, num);

    setFormData(prev => {
      const newSizes = { ...(prev.sizes || {}), [size]: cleanNum };
      const newTotal = Object.values(newSizes).reduce((sum, val) => sum + (val || 0), 0);
      return { ...prev, sizes: newSizes, total: newTotal };
    });
  };

  const saveInventory = () => {
    if (!formData.productType || !formData.model) return;

    const finalCount: InventoryCount = {
      id: editingId || crypto.randomUUID(),
      productType: formData.productType,
      model: formData.model,
      brand: formData.brand || '',
      color: formData.color || '',
      observations: formData.observations || '',
      gridType: formData.gridType as SizeGridType,
      sizes: formData.sizes as Record<string, number>,
      total: formData.total || 0,
      createdAt: editingId 
        ? counts.find(c => c.id === editingId)?.createdAt || Date.now() 
        : Date.now()
    };

    if (editingId) {
      setCounts(prev => prev.map(c => c.id === editingId ? finalCount : c));
    } else {
      setCounts(prev => [finalCount, ...prev]);
    }

    setCurrentView(AppView.HOME);
  };

  const generatePDF = () => {
    window.print();
  };

  // Filtered counts
  const filteredCounts = useMemo(() => {
    if (!searchTerm) return counts;
    const low = searchTerm.toLowerCase();
    return counts.filter(c => 
      c.productType.toLowerCase().includes(low) || 
      c.model.toLowerCase().includes(low) || 
      c.brand?.toLowerCase().includes(low)
    );
  }, [counts, searchTerm]);

  return (
    <div className="min-h-screen flex flex-col max-w-lg mx-auto bg-white shadow-xl relative">
      {/* HEADER (No Print) */}
      <header className="no-print bg-indigo-600 text-white p-4 sticky top-0 z-50 flex items-center justify-between shadow-md">
        <div className="flex items-center gap-2">
          <Package size={24} />
          <h1 className="font-bold text-lg uppercase tracking-tight">Ideal Tecidos</h1>
        </div>
        {currentView !== AppView.HOME && (
          <button 
            onClick={() => setCurrentView(AppView.HOME)}
            className="p-1 hover:bg-indigo-500 rounded"
          >
            <XCircle size={24} />
          </button>
        )}
      </header>

      {/* VIEWS */}
      <main className="flex-1 p-4 pb-24 no-print">
        {currentView === AppView.HOME && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <div className="flex flex-col gap-4">
              <button 
                onClick={handleStartNew}
                className="bg-indigo-600 text-white py-4 px-6 rounded-2xl shadow-lg flex items-center justify-center gap-3 active:scale-95 transition-transform"
              >
                <Plus size={24} />
                <span className="text-lg font-bold">Nova Contagem</span>
              </button>

              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text"
                  placeholder="Buscar tipo, modelo ou marca..."
                  className="w-full pl-10 pr-4 py-3 bg-gray-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between border-b pb-2">
                <h2 className="text-gray-500 font-semibold flex items-center gap-2">
                  <History size={18} /> Histórico de Contagem
                </h2>
                <span className="text-xs bg-gray-200 px-2 py-1 rounded-full text-gray-600">
                  {filteredCounts.length} itens
                </span>
              </div>

              {filteredCounts.length === 0 ? (
                <div className="text-center py-12 text-gray-400">
                  <p>Nenhuma contagem encontrada.</p>
                </div>
              ) : (
                filteredCounts.map((item) => (
                  <div key={item.id} className="bg-white border rounded-xl p-4 shadow-sm hover:border-indigo-200 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <div>
                        <h3 className="font-bold text-indigo-900">{item.productType}</h3>
                        <p className="text-sm text-gray-600">Ref: {item.model}</p>
                      </div>
                      <div className="flex gap-2">
                        <button 
                          onClick={() => handleEdit(item)}
                          className="p-2 text-blue-600 bg-blue-50 rounded-lg"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => handleDelete(item.id)}
                          className="p-2 text-red-600 bg-red-50 rounded-lg"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                    <div className="flex justify-between items-end mt-4">
                      <div className="text-xs text-gray-400">
                        {new Date(item.createdAt).toLocaleString('pt-BR')}
                      </div>
                      <div className="bg-indigo-100 text-indigo-700 font-bold px-3 py-1 rounded-full text-sm">
                        Total: {item.total}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {currentView === AppView.IDENTIFY && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div className="flex items-center gap-2 mb-4">
              <button onClick={() => setCurrentView(AppView.HOME)} className="text-indigo-600">
                <ChevronLeft size={24} />
              </button>
              <h2 className="text-xl font-bold">Identificação do Produto</h2>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Produto *</label>
                <select 
                  className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none appearance-none"
                  value={formData.productType}
                  onChange={(e) => setFormData(prev => ({ ...prev, productType: e.target.value }))}
                >
                  <option value="">Selecione...</option>
                  {PRODUCT_TYPES.map(type => <option key={type} value={type}>{type}</option>)}
                  <option value="Outro">Outro...</option>
                </select>
                {formData.productType === 'Outro' && (
                  <input 
                    type="text" 
                    placeholder="Digite o tipo de produto"
                    className="w-full mt-2 p-3 bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    onChange={(e) => setFormData(prev => ({ ...prev, productType: e.target.value }))}
                  />
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Modelo / Referência *</label>
                <input 
                  type="text"
                  placeholder="Ex: Ref 1012"
                  className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  value={formData.model}
                  onChange={(e) => setFormData(prev => ({ ...prev, model: e.target.value }))}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Marca (Opcional)</label>
                  <input 
                    type="text"
                    className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    value={formData.brand}
                    onChange={(e) => setFormData(prev => ({ ...prev, brand: e.target.value }))}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Cor (Opcional)</label>
                  <input 
                    type="text"
                    className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    value={formData.color}
                    onChange={(e) => setFormData(prev => ({ ...prev, color: e.target.value }))}
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Observações</label>
                <textarea 
                  className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none h-24"
                  value={formData.observations}
                  onChange={(e) => setFormData(prev => ({ ...prev, observations: e.target.value }))}
                />
              </div>

              <div className="bg-gray-100 p-4 rounded-xl">
                <label className="block text-sm font-medium text-gray-700 mb-3">Grade de Tamanhos</label>
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={() => setFormData(prev => ({ ...prev, gridType: 'LETTER' }))}
                    className={`py-3 rounded-lg text-sm font-bold border-2 transition-all ${formData.gridType === 'LETTER' ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-gray-500 border-gray-200'}`}
                  >
                    Por Letras (P, M, G...)
                  </button>
                  <button 
                    onClick={() => setFormData(prev => ({ ...prev, gridType: 'NUMERIC' }))}
                    className={`py-3 rounded-lg text-sm font-bold border-2 transition-all ${formData.gridType === 'NUMERIC' ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-gray-500 border-gray-200'}`}
                  >
                    Numérico (34, 36...)
                  </button>
                </div>
              </div>

              <button 
                disabled={!formData.productType || !formData.model}
                onClick={() => setCurrentView(AppView.COUNT)}
                className="w-full bg-indigo-600 text-white py-4 rounded-xl shadow-lg font-bold disabled:opacity-50 disabled:grayscale transition-all active:scale-95"
              >
                Próxima Etapa: Contagem
              </button>
            </div>
          </div>
        )}

        {currentView === AppView.COUNT && (
          <div className="space-y-6 animate-in slide-in-from-right duration-300">
            <div className="flex items-center gap-2 mb-4">
              <button onClick={() => setCurrentView(AppView.IDENTIFY)} className="text-indigo-600">
                <ChevronLeft size={24} />
              </button>
              <div>
                <h2 className="text-xl font-bold">Contagem Manual</h2>
                <p className="text-xs text-gray-500 uppercase font-semibold">{formData.productType} - {formData.model}</p>
              </div>
            </div>

            <div className="bg-gray-50 border rounded-2xl p-4">
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                {(formData.gridType === 'LETTER' ? LETTER_SIZES : NUMERIC_SIZES).map(size => (
                  <div key={size} className="flex flex-col">
                    <label className="text-xs font-bold text-gray-500 mb-1 ml-1">{size}</label>
                    <input 
                      type="number"
                      inputMode="numeric"
                      min="0"
                      className="w-full p-4 border rounded-xl text-center text-xl font-bold bg-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      value={formData.sizes?.[size] || ''}
                      onChange={(e) => updateSizeCount(size, e.target.value)}
                      placeholder="0"
                    />
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-indigo-900 text-white p-6 rounded-2xl shadow-xl flex items-center justify-between">
              <div>
                <p className="text-indigo-300 text-sm font-bold uppercase">Total Geral</p>
                <p className="text-4xl font-black">{formData.total}</p>
              </div>
              <button 
                onClick={saveInventory}
                className="bg-green-500 text-white py-4 px-8 rounded-xl font-bold flex items-center gap-2 shadow-lg active:scale-95"
              >
                <Save size={20} /> Finalizar
              </button>
            </div>
          </div>
        )}
      </main>

      {/* FOOTER ACTIONS (No Print) */}
      <footer className="no-print fixed bottom-0 left-0 right-0 max-w-lg mx-auto bg-white border-t p-4 flex gap-4">
        {currentView === AppView.HOME && (
          <button 
            onClick={generatePDF}
            className="flex-1 bg-gray-800 text-white py-4 rounded-xl flex items-center justify-center gap-2 font-bold active:scale-95 transition-all shadow-md"
          >
            <FileText size={20} /> Baixar PDF
          </button>
        )}
      </footer>

      {/* PRINT REPORT (Hidden on screen, visible on print) */}
      <div className="print-only">
        <div className="mb-8 border-b-2 border-indigo-600 pb-4 flex justify-between items-end">
          <div>
            <h1 className="text-2xl font-black text-indigo-900">IDEAL TECIDOS</h1>
            <p className="text-gray-500 text-sm">Relatório de Contagem de Estoque</p>
          </div>
          <div className="text-right text-xs text-gray-400">
            Gerado em: {new Date().toLocaleString('pt-BR')}
          </div>
        </div>

        <table className="w-full text-sm border-collapse">
          <thead>
            <tr className="bg-gray-100">
              <th className="border p-2 text-left">Data</th>
              <th className="border p-2 text-left">Produto</th>
              <th className="border p-2 text-left">Ref/Modelo</th>
              <th className="border p-2 text-left">Marca/Cor</th>
              <th className="border p-2 text-left">Grade Detalhada</th>
              <th className="border p-2 text-center">Total</th>
            </tr>
          </thead>
          <tbody>
            {filteredCounts.map(item => (
              <tr key={item.id}>
                <td className="border p-2 text-xs">
                  {new Date(item.createdAt).toLocaleDateString('pt-BR')}
                </td>
                <td className="border p-2 font-bold">{item.productType}</td>
                <td className="border p-2">{item.model}</td>
                <td className="border p-2 text-xs">
                  {item.brand && `Marca: ${item.brand}`}
                  {item.brand && item.color && <br />}
                  {item.color && `Cor: ${item.color}`}
                </td>
                <td className="border p-2">
                  <div className="flex flex-wrap gap-2">
                    {Object.entries(item.sizes)
                      .filter(([_, qty]) => qty > 0)
                      .map(([size, qty]) => (
                        <span key={size} className="bg-gray-100 px-2 py-0.5 rounded border text-[10px]">
                          <strong>{size}:</strong> {qty}
                        </span>
                      ))}
                  </div>
                </td>
                <td className="border p-2 text-center font-bold">{item.total}</td>
              </tr>
            ))}
          </tbody>
          <tfoot>
            <tr className="bg-indigo-50 font-bold">
              <td colSpan={5} className="border p-2 text-right">TOTAL GERAL EM ESTOQUE</td>
              <td className="border p-2 text-center text-lg text-indigo-900">
                {filteredCounts.reduce((sum, item) => sum + item.total, 0)}
              </td>
            </tr>
          </tfoot>
        </table>

        <div className="mt-12 pt-8 border-t text-center text-xs text-gray-400">
          Este documento é um registro manual de estoque para uso interno.
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  Package, 
  History, 
  Plus, 
  Trash2, 
  Edit2, 
  ChevronLeft, 
  Save, 
  FileText, 
  Search,
  XCircle
} from 'lucide-react';
import { AppView, InventoryCount, SizeGridType } from './types';
import { PRODUCT_TYPES, LETTER_SIZES, NUMERIC_SIZES } from './constants';

const App: React.FC = () => {
  // Persistence state
  const [counts, setCounts] = useState<InventoryCount[]>(() => {
    const saved = localStorage.getItem('ideal_tecidos_inventory');
    return saved ? JSON.parse(saved) : [];
  });

  // UI state
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);
  const [searchTerm, setSearchTerm] = useState('');

  // Form state
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<InventoryCount>>({
    productType: '',
    model: '',
    brand: '',
    color: '',
    observations: '',
    gridType: 'LETTER',
    sizes: {},
    total: 0
  });

  // Save to localStorage
  useEffect(() => {
    localStorage.setItem('ideal_tecidos_inventory', JSON.stringify(counts));
  }, [counts]);

  // Handlers
  const handleStartNew = () => {
    setFormData({
      productType: '',
      model: '',
      brand: '',
      color: '',
      observations: '',
      gridType: 'LETTER',
      sizes: {},
      total: 0
    });
    setEditingId(null);
    setCurrentView(AppView.IDENTIFY);
  };

  const handleEdit = (count: InventoryCount) => {
    setFormData({ ...count });
    setEditingId(count.id);
    setCurrentView(AppView.IDENTIFY);
  };

  const handleDelete = (id: string) => {
    if (confirm('Tem certeza que deseja excluir esta contagem?')) {
      setCounts(prev => prev.filter(c => c.id !== id));
    }
  };

  const updateSizeCount = (size: string, value: string) => {
    const num = parseInt(value, 10) || 0;
    const cleanNum = Math.max(0, num);

    setFormData(prev => {
      const newSizes = { ...(prev.sizes || {}), [size]: cleanNum };
      // Fix: Add explicit typing to reduce parameters to avoid "operator + cannot be applied to unknown"
      const newTotal = Object.values(newSizes).reduce((sum: number, val: any) => sum + (val || 0), 0);
      return { ...prev, sizes: newSizes, total: newTotal };
    });
  };

  const saveInventory = () => {
    if (!formData.productType || !formData.model) return;

    const finalCount: InventoryCount = {
      id: editingId || crypto.randomUUID(),
      productType: formData.productType,
      model: formData.model,
      brand: formData.brand || '',
      color: formData.color || '',
      observations: formData.observations || '',
      gridType: formData.gridType as SizeGridType,
      sizes: formData.sizes as Record<string, number>,
      total: formData.total || 0,
      createdAt: editingId 
        ? counts.find(c => c.id === editingId)?.createdAt || Date.now() 
        : Date.now()
    };

    if (editingId) {
      setCounts(prev => prev.map(c => c.id === editingId ? finalCount : c));
    } else {
      setCounts(prev => [finalCount, ...prev]);
    }

    setCurrentView(AppView.HOME);
  };

  const generatePDF = () => {
    window.print();
  };

  // Filtered counts
  const filteredCounts = useMemo(() => {
    if (!searchTerm) return counts;
    const low = searchTerm.toLowerCase();
    return counts.filter(c => 
      c.productType.toLowerCase().includes(low) || 
      c.model.toLowerCase().includes(low) || 
      c.brand?.toLowerCase().includes(low)
    );
  }, [counts, searchTerm]);

  return (
    <div className="min-h-screen flex flex-col max-w-lg mx-auto bg-white shadow-xl relative">
      {/* HEADER (No Print) */}
      <header className="no-print bg-indigo-600 text-white p-4 sticky top-0 z-50 flex items-center justify-between shadow-md">
        <div className="flex items-center gap-2">
          <Package size={24} />
          <h1 className="font-bold text-lg uppercase tracking-tight">Ideal Tecidos</h1>
        </div>
        {currentView !== AppView.HOME && (
          <button 
            onClick={() => setCurrentView(AppView.HOME)}
            className="p-1 hover:bg-indigo-500 rounded"
          >
            <XCircle size={24} />
          </button>
        )}
      </header>

      {/* VIEWS */}
      <main className="flex-1 p-4 pb-24 no-print">
        {currentView === AppView.HOME && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <div className="flex flex-col gap-4">
              <button 
                onClick={handleStartNew}
                className="bg-indigo-600 text-white py-4 px-6 rounded-2xl shadow-lg flex items-center justify-center gap-3 active:scale-95 transition-transform"
              >
                <Plus size={24} />
                <span className="text-lg font-bold">Nova Contagem</span>
              </button>

              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text"
                  placeholder="Buscar tipo, modelo ou marca..."
                  className="w-full pl-10 pr-4 py-3 bg-gray-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between border-b pb-2">
                <h2 className="text-gray-500 font-semibold flex items-center gap-2">
                  <History size={18} /> Histórico de Contagem
                </h2>
                <span className="text-xs bg-gray-200 px-2 py-1 rounded-full text-gray-600">
                  {filteredCounts.length} itens
                </span>
              </div>

              {filteredCounts.length === 0 ? (
                <div className="text-center py-12 text-gray-400">
                  <p>Nenhuma contagem encontrada.</p>
                </div>
